```class Solution {
    public int kthFactor(int n, int k) {
        int[] factors = new int[k];
        int i = 1;
        while (i * i <= n) {
            if (n % i == 0) {
                factors[--k] = i;
            }
            i++;
        }
        if (k > 0) {
            return factors[k - 1];
        } else {
            return -1;
        }
    }
}
```

